from pathlib import Path

from docx import Document
from docx.enum.text import WD_BREAK
from docx.shared import Inches, Pt
from docx.enum.style import WD_STYLE_TYPE


OUT = Path("research/youtube/outputs/first_batch")
OUT.mkdir(parents=True, exist_ok=True)


def setup_doc(title: str, subtitle: str) -> Document:
    doc = Document()
    section = doc.sections[0]
    section.top_margin = Inches(1)
    section.bottom_margin = Inches(1)
    section.left_margin = Inches(1)
    section.right_margin = Inches(1)

    styles = doc.styles
    normal = styles["Normal"]
    normal.font.name = "Arial"
    normal.font.size = Pt(11)
    normal.paragraph_format.space_after = Pt(8)
    normal.paragraph_format.line_spacing = 1.15

    for name, size, before, after in [
        ("Heading 1", 20, 18, 8),
        ("Heading 2", 16, 14, 6),
        ("Heading 3", 13, 10, 4),
    ]:
        st = styles[name]
        st.font.name = "Arial"
        st.font.size = Pt(size)
        st.font.bold = False
        st.paragraph_format.space_before = Pt(before)
        st.paragraph_format.space_after = Pt(after)

    if "ScriptBody" not in styles:
        s = styles.add_style("ScriptBody", WD_STYLE_TYPE.PARAGRAPH)
        s.base_style = styles["Normal"]
        s.font.name = "Arial"
        s.font.size = Pt(11.5)
        s.paragraph_format.line_spacing = 1.18
        s.paragraph_format.space_after = Pt(10)

    if "BriefBullet" not in styles:
        s = styles.add_style("BriefBullet", WD_STYLE_TYPE.PARAGRAPH)
        s.base_style = styles["Normal"]
        s.font.name = "Arial"
        s.font.size = Pt(10.5)
        s.paragraph_format.left_indent = Inches(0.25)
        s.paragraph_format.first_line_indent = Inches(-0.15)
        s.paragraph_format.space_after = Pt(5)

    p = doc.add_paragraph()
    p.paragraph_format.space_after = Pt(3)
    r = p.add_run(title)
    r.font.name = "Arial"
    r.font.size = Pt(26)
    r.bold = False

    p = doc.add_paragraph()
    p.paragraph_format.space_after = Pt(18)
    r = p.add_run(subtitle)
    r.font.name = "Arial"
    r.font.size = Pt(11)
    r.italic = True
    return doc


def add_script(doc: Document, title: str, meta: str, text: str):
    doc.add_heading(title, level=1)
    p = doc.add_paragraph(meta)
    p.runs[0].italic = True
    for para in [x.strip() for x in text.strip().split("\n\n") if x.strip()]:
        doc.add_paragraph(para, style="ScriptBody")


def add_bullets(doc: Document, items):
    for item in items:
        doc.add_paragraph("• " + item, style="BriefBullet")


