def make_scripts_doc():
    doc = setup_doc(
        "AtlasRepo First Batch Scripts",
        "Дословные сценарии для 3 long-form видео и 10 Shorts. Версия для чтения по субтитрам."
    )
    doc.add_heading("Как читать", level=1)
    doc.add_paragraph(
        "Long-form сценарии написаны как последовательная речь. Заголовки нужны только для навигации в документе. "
        "Внутри видео не нужно зачитывать слова 'акт' или 'структура'. Shorts можно читать почти дословно; "
        "темп должен быть живой, но без скороговорки."
    )

    add_script(doc, "Video 1. These 10 GitHub Repos Can Build a One-Person AI Company", "Ориентир: 10-15 минут с демонстрациями. Первые 30 секунд — самый сильный хук.", video1)
    add_script(doc, "Video 2. I Created a Micro-SaaS in One Evening with Open-Source Projects", "Ориентир: 10-15 минут. Конкретный micro-SaaS: Open-Source Tool Radar for Content Creators.", video2)
    add_script(doc, "Video 3. This Website Found 3 Gold GitHub Repos for a Content Factory", "Ориентир: 8-12 минут. Это нативный обзор AtlasRepo через задачу.", video3)

    doc.add_page_break()
    doc.add_heading("10 Shorts. Дословные сценарии", level=1)
    for i, (name, text) in enumerate(shorts, 1):
        add_script(doc, f"Short #{i}. {name}", "Ориентир: 35-60 секунд. Сильный общий хук, без узкой dev-лекции.", text)

    doc.add_page_break()
    doc.add_heading("Self-audit after two passes", level=1)
    for para in [x.strip() for x in audit_notes.strip().split("\n\n") if x.strip()]:
        doc.add_paragraph(para, style="ScriptBody")
    path = OUT / "atlasrepo_first_batch_read_aloud_scripts.docx"
    doc.save(path)
    return path


